$(document).ready(function(){new Typed(".hero-typed-text",{stringsElement:".hero-text",typeSpeed:40});$(".mouse-scroll").click(function(){$("html, body").animate({scrollTop:$("#about-me").offset().top},1e3)}),$(".wpcf7-form-control").on("keyup",function(){if($(this).val()){var e=$(this).parents(".form-field").children(".input-label");$(e).addClass("not-empty")}else{e=$(this).parents(".form-field").children(".input-label");$(e).removeClass("not-empty")}}),$(".wpcf7-form-control").on("focusin",function(){var e=$(this).parents(".form-field").children(".input-label");$(e).addClass("not-empty")}),$(".wpcf7-form-control").on("focusout",function(){var e=$(this).parents(".form-field").children(".input-label");$(e).removeClass("not-empty")})});